Search : HighLevel Support Portal
/* theme */ .portal--light {
--fw-body-bg: #F5F7F9;
--fw-header-bg: #F5F7F9;
--fw-header-text-color: #12344D;
--fw-helpcenter-bg: #1c48a6;
--fw-helpcenter-text-color: #FFFFFF;
--fw-footer-bg: #1c48a6;
--fw-footer-text-color: #FFFFFF;
--fw-tab-active-color: #1c48a6;
--fw-tab-active-text-color: #FFFFFF;
--fw-tab-hover-color: #FFFFFF;
--fw-tab-hover-text-color: #12344D;
--fw-btn-background: #FFFFFF;
--fw-btn-text-color: #12344D;
--fw-btn-primary-background: #1c48a6;
--fw-btn-primary-text-color: #FFFFFF;
--fw-baseFont: Source Sans Pro;
--fw-textColor: #000000;
--fw-headingsFont: Source Sans Pro;
--fw-linkColor: #1c48a6;
--fw-linkColorHover: #7096e6;
--fw-inputFocusRingColor: #EBEFF3;
--fw-formInputFocusColor: #EBEFF3;
--fw-card-bg: #FFFFFF;
--fw-card-fg: #000000;
--fw-card-border-color: #EBEFF3;
--fw-nonResponsive: #F5F7F9;
--bs-body-font-family: Source Sans Pro;
}
#helpdesk_ticket_priority,
label.control-label.priority-label {
display: none;
}

p, ol, ul, li, a {
font-size: 16px !important;
line-height: 20px !important;
}

body hr {
color: #9ba1a7 !important;
margin-top: 50px !important;
margin-bottom: 50px !important;
}

.fw-content a {
color: #1c48a6 !important; /* Set your desired link color here */
}

.fw-content a:hover {
color: #7096e6 !important; /* Set hover color here */
text-decoration: underline; /* Optional: removes underline on hover */
}

underline-text {
text-decoration: underline;
}

h1  {

font-size:36px !important;
line-height:43.75px !important;
}

h2 {
font-size: 30px !important;
line-height: 35px !important;
color: #000000 !important;
}

h2 a {
font-size:30px !important;
}

h3 {
font-size: 24px !important;
line-height: 30px !important;
color: #000000 !important;
}

h3 a {
font-size:24px !important;
}

h4 {
font-size: 18px !important;
line-height: 25px !important;
color: #000000 !important;
}

span img {
font-size: inherit !important;
width: auto !important;
height: auto !important;
}

